market_data.price:
Current: ${price[current_price]} ({price[change_pct]:+.2f}% today)
52w range: ${price[low_52w]} – ${price[high_52w]} | Distance from 52w high: {price[pct_from_52w_high]}%
SMA 20/50: {price[sma_20]} / {price[sma_50]}
RSI-14: {price[rsi_14]} | ATR-14: {price[atr_14]}
Relative volume: {price[relative_volume]}x | Signal: {price[cross_signal]}

market_data.fundamentals:
{fund[company_name]} | {fund[sector]} | {fund[industry]}
Market cap: {fund[market_cap_fmt]} | Beta: {fund[beta]}
P/E: {fund[pe_trailing]} (fwd {fund[pe_forward]}) | PEG: {fund[peg_ratio]} | P/B: {fund[price_to_book]}
EV/EBITDA: {fund[ev_to_ebitda]} | EV/Revenue: {fund[ev_to_revenue]}
Net margin: {fund[net_margin]} | Operating margin: {fund[operating_margin]}
ROE: {fund[return_on_equity]} | D/E: {fund[debt_to_equity]} | Current ratio: {fund[current_ratio]}
Revenue TTM: {fund[revenue_ttm_fmt]} | FCF: {fund[free_cash_flow_fmt]}
Short float: {fund[short_float_pct]} | Dividend yield: {fund[dividend_yield]}
